patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index 04ea12ef0f12..2069b50c7f74 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -13,6 +13,7 @@
 //===----------------------------------------------------------------------===//

 #include "llvm/Transforms/Vectorize/VectorCombine.h"
+#include <optional>
 #include "llvm/ADT/DenseMap.h"
 #include "llvm/ADT/STLExtras.h"
 #include "llvm/ADT/ScopeExit.h"
@@ -38,6 +39,21 @@
 #include "llvm/Transforms/Utils/InstructionWorklist.h"

 using namespace llvm;
+
+// PR115575 fix: guard scalarization on in-range insertelement index
+static std::optional<unsigned> getInRangeConstIndex(Value *IdxVal, unsigned NumElts) {
+  if (auto *CI = dyn_cast<ConstantInt>(IdxVal)) {
+    // Negative indices or larger-than-numelts are OOB.
+    // ConstantInt is unsigned compare safe via getLimitedValue.
+    APInt A = CI->getValue();
+    if (A.isIntN(64)) {
+      uint64_t U = A.getZExtValue();
+      if (U < NumElts)
+        return (unsigned)U;
+    }
+  }
+  return std::nullopt;
+}
 using namespace llvm::PatternMatch;

 STATISTIC(NumVecLoad, "Number of vector loads formed");
@@ -911,6 +927,27 @@ bool VectorCombine::scalarizeVPIntrinsic(Instruction &I) {
 /// Match a vector binop or compare instruction with at least one inserted
 /// scalar operand and convert to scalar binop/cmp followed by insertelement.
 bool VectorCombine::scalarizeBinopOrCmp(Instruction &I) {
+  // PR115575 GUARD: Bail out of scalarization if insertelement uses an OOB constant index.
+  auto GuardOOBInsertIdx = [&](Value *Op) -> bool {
+    if (auto *IE = dyn_cast<InsertElementInst>(Op)) {
+      if (auto *FVT = dyn_cast<FixedVectorType>(IE->getType())) {
+        unsigned NumElts = FVT->getNumElements();
+        auto Idx = getInRangeConstIndex(IE->getOperand(2), NumElts);
+        if (!Idx)
+          return false; // OOB index detected
+      }
+    }
+    return true;
+  };
+  bool IsBinOrCmp = Instruction::isBinaryOp(I.getOpcode()) ||
+                    I.getOpcode() == Instruction::ICmp ||
+                    I.getOpcode() == Instruction::FCmp;
+  if (IsBinOrCmp) {
+    if (!GuardOOBInsertIdx(I.getOperand(0)) ||
+        !GuardOOBInsertIdx(I.getOperand(1)))
+      return false;
+  }
+
   CmpInst::Predicate Pred = CmpInst::BAD_ICMP_PREDICATE;
   Value *Ins0, *Ins1;
   if (!match(&I, m_BinOp(m_Value(Ins0), m_Value(Ins1))) &&
@@ -2915,4 +2952,4 @@ PreservedAnalyses VectorCombinePass::run(Function &F,
   PreservedAnalyses PA;
   PA.preserveSet<CFGAnalyses>();
   return PA;
-}
+}
\ No newline at end of file

